from typing import List, Tuple
import heapq
from collections import deque
import random


class Solution:
    def can_reach_bank(
        self,
        grid: List[List[int]],
        police: List[Tuple[int, int, int]],  # (row, col, radius)
        thief: Tuple[int, int],
        bank: Tuple[int, int],
    ) -> bool:
        if not grid or not grid[0]:
            return False
        rows, cols = len(grid), len(grid[0])
        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

        # ---- Phase 1: paint patrolled cells (Manhattan flood, walls IGNORED) ----
        patrolled = [[False] * cols for _ in range(rows)]
        best_budget = [[-1] * cols for _ in range(rows)]
        max_heap: List[Tuple[int, int, int]] = []  # (-remaining_budget, r, c)
        for (pr, pc, k) in police:
            if 0 <= pr < rows and 0 <= pc < cols and k > best_budget[pr][pc]:
                best_budget[pr][pc] = k
                heapq.heappush(max_heap, (-k, pr, pc))

        while max_heap:
            neg_budget, r, c = heapq.heappop(max_heap)
            budget = -neg_budget
            if budget < best_budget[r][c]:
                continue  # stale entry
            patrolled[r][c] = True
            if budget == 0:
                continue
            for dr, dc in directions:
                nr, nc = r + dr, c + dc
                if 0 <= nr < rows and 0 <= nc < cols and budget - 1 > best_budget[nr][nc]:
                    best_budget[nr][nc] = budget - 1
                    heapq.heappush(max_heap, (-(budget - 1), nr, nc))

        tr, tc = thief
        br, bc = bank

        def walkable(r: int, c: int) -> bool:
            return 0 <= r < rows and 0 <= c < cols and grid[r][c] == 0 and not patrolled[r][c]

        if not walkable(tr, tc) or not walkable(br, bc):
            return False
        if (tr, tc) == (br, bc):
            return True

        # ---- Phase 2: BFS reachability (walls BLOCK) ----
        visited = [[False] * cols for _ in range(rows)]
        visited[tr][tc] = True
        queue = deque([(tr, tc)])
        while queue:
            r, c = queue.popleft()
            for dr, dc in directions:
                nr, nc = r + dr, c + dc
                if walkable(nr, nc) and not visited[nr][nc]:
                    if (nr, nc) == (br, bc):
                        return True
                    visited[nr][nc] = True
                    queue.append((nr, nc))
        return False


# ---------------- brute-force oracle ----------------
def brute(grid, police, thief, bank):
    rows, cols = len(grid), len(grid[0])
    patrolled = [[False] * cols for _ in range(rows)]
    for r in range(rows):
        for c in range(cols):
            for (pr, pc, k) in police:
                if abs(r - pr) + abs(c - pc) <= k:
                    patrolled[r][c] = True
                    break
    tr, tc = thief; br, bc = bank

    def walkable(r, c):
        return 0 <= r < rows and 0 <= c < cols and grid[r][c] == 0 and not patrolled[r][c]

    if not walkable(tr, tc) or not walkable(br, bc):
        return False
    seen = {(tr, tc)}
    stack = [(tr, tc)]
    while stack:
        r, c = stack.pop()
        if (r, c) == (br, bc):
            return True
        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r + dr, c + dc
            if walkable(nr, nc) and (nr, nc) not in seen:
                seen.add((nr, nc)); stack.append((nr, nc))
    return (tr, tc) == (br, bc)


sol = Solution()

# --- sample / hand cases ---
g5 = [[0] * 5 for _ in range(5)]
print("station(2,2)k1 ->", sol.can_reach_bank(g5, [(2, 2, 1)], (0, 0), (4, 4)))  # expect True
print("station(2,2)k2 ->", sol.can_reach_bank(g5, [(2, 2, 2)], (0, 0), (4, 4)))  # check
g3 = [[0] * 3 for _ in range(3)]
print("wall row k0 ->", sol.can_reach_bank(g3, [(1, 0, 0), (1, 1, 0), (1, 2, 0)], (0, 0), (2, 2)))  # expect False
print("thief patrolled ->", sol.can_reach_bank(g5, [(0, 0, 0)], (0, 0), (4, 4)))  # expect False
print("thief==bank free ->", sol.can_reach_bank(g5, [(2, 2, 1)], (1, 1), (1, 1)))  # expect True
# obstacle wall
gw = [[0, 1, 0], [0, 1, 0], [0, 1, 0]]
print("solid wall col ->", sol.can_reach_bank(gw, [], (0, 0), (0, 2)))  # expect False
print("no police open ->", sol.can_reach_bank(g5, [], (0, 0), (4, 4)))  # expect True

# --- randomized fuzz against brute oracle ---
random.seed(7)
mismatch = 0
for _ in range(4000):
    R = random.randint(1, 6); C = random.randint(1, 6)
    grid = [[random.randint(0, 0) if random.random() < 0.8 else 1 for _ in range(C)] for _ in range(R)]
    P = random.randint(0, 4)
    police = [(random.randint(0, R - 1), random.randint(0, C - 1), random.randint(0, 4)) for _ in range(P)]
    thief = (random.randint(0, R - 1), random.randint(0, C - 1))
    bank = (random.randint(0, R - 1), random.randint(0, C - 1))
    if sol.can_reach_bank(grid, police, thief, bank) != brute(grid, police, thief, bank):
        mismatch += 1
        if mismatch <= 3:
            print("MISMATCH", R, C, grid, police, thief, bank)
print("fuzz mismatches:", mismatch)
